import csv,re
terms=['Venezuela','Maduro','Caracas','Colombia','oil','armada','Latin America','regime change','Delcy Rodriguez','Machado']
for term in terms:
    hits=[]
    for r in csv.DictReader(open('market.csv', newline='')):
        if r['is_resolved']=='False' and re.search(re.escape(term), r['title']+' '+(r.get('background') or '')+' '+(r.get('resolution_criteria') or ''), re.I):
            hits.append(r)
    if hits:
        print('\\nTERM',term,'hits',len(hits))
        for r in hits[:12]: print(r['qid'], r['title'][:190], '| pred', r['my_prediction'])
PY"

